#include <stdio.h>
#include <stdlib.h>

void generate(int n, char *buf, int pos) {
    if (pos == n) {
        buf[pos] = '\0';
        puts(buf);
        return;
    }
    buf[pos] = '0';
    generate(n, buf, pos + 1);
    if (pos == 0 || buf[pos - 1] == '0') {
        buf[pos] = '1';
        generate(n, buf, pos + 1);
    }
}

int main() {
    int T, n;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) break;
        char *buf = (char *)malloc((n + 1) * sizeof(char));
        generate(n, buf, 0);
        free(buf);
    }
    return 0;
}

