#include <bits/stdc++.h>
using namespace std;

void generate(int n, string &cur) {
    if ((int)cur.size() == n) {
        cout << cur << '\n';
        return;
    }
    cur.push_back('0');
    generate(n, cur);
    cur.pop_back();
    if (cur.empty() || cur.back() == '0') {
        cur.push_back('1');
        generate(n, cur);
        cur.pop_back();
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T, n;
    if (!(cin >> T)) return 0;
    while (T--) {
        cin >> n;
        string cur;
        generate(n, cur);
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static void generate(int n, StringBuilder sb, BufferedWriter out) throws IOException {
        if (sb.length() == n) {
            out.write(sb.toString());
            out.newLine();
            return;
        }
        sb.append('0');
        generate(n, sb, out);
        sb.deleteCharAt(sb.length() - 1);
        if (sb.length() == 0 || sb.charAt(sb.length() - 1) == '0') {
            sb.append('1');
            generate(n, sb, out);
            sb.deleteCharAt(sb.length() - 1);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        BufferedWriter out = new BufferedWriter(new OutputStreamWriter(System.out));
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            int n = Integer.parseInt(br.readLine().trim());
            generate(n, new StringBuilder(), out);
        }
        out.flush();
    }
}

code.Python3:
import sys

def generate(n, prefix, out):
    if len(prefix) == n:
        out.append(prefix)
        return
    generate(n, prefix + '0', out)
    if not prefix or prefix[-1] == '0':
        generate(n, prefix + '1', out)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        generate(n, '', out_lines)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

